      // After a short delay, set another key which should trigger _flush
      setTimeout(() => {
        db.set('finalKey', { value: 'final' }, () => {
          if (!drainEmitted) {
            done(new Error('Drain event was not emitted when expected'));
          }
        });
      }, 100);
    });

    db.on('drain', () => {
      drainEmitted = true;
    });

    // Safety timeout
